fn factorial(n: i32) -> Result<u128, &'static str> {
    if n < 0 {
        return Err("El número debe ser no negativo");
    }
    if n == 0 {
        return Ok(1);
    }

    factorial(n - 1).map(|res| res * n as u128)
}

fn main() {
    let test_cases = [5, 0, -5];

    for &n in &test_cases {
        match factorial(n) {
            Ok(result) => println!("El factorial de {} es {}", n, result),
            Err(e) => println!("Error para {}: {}", n, e),
        }
    }
}
