/**
 * Realiza una solicitud GET con lógica de reintentos.
 * 
 * @param {string} url - La URL de la API.
 * @param {number} maxRetries - Número máximo de intentos (por defecto 3).
 * @param {number} delay - Tiempo de espera entre reintentos en ms (por defecto 1000).
 * @returns {Promise<any>} - La respuesta JSON procesada.
 */
const fetchDataWithRetry = async (url, maxRetries = 3, delay = 1000) => {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      const isLastAttempt = attempt === maxRetries;

      if (isLastAttempt) {
        console.error(`[Error] Fallo tras ${maxRetries} intentos: ${error.message}`);
        throw error;
      }

      console.warn(`[Retry] Intento ${attempt} fallido. Reintentando en ${delay}ms...`);

      // Espera antes del siguiente reintento (Exponential backoff opcional)
      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }
};

// Ejemplo de uso:
(async () => {
  const API_URL = 'https://jsonplaceholder.typicode.com/todos/1';

  try {
    const data = await fetchDataWithRetry(API_URL);
    console.log('Datos recibidos:', data);
  } catch (err) {
    console.error('Operación fallida definitivamente:', err.message);
  }
})();
